var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……리브 경.","JPN":"……リブ卿。","ENG":"...Dame Liv.","TWN":"……莉芙。"},"stage":{"bg":"TOMB","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"왔어, 부단장? 안 그래도 지금 아저씨들한테 헌화하던 참이야.","JPN":"来たんだね、副団長？　ちょうど今、おじさんたちに献花してたとこだよ。","ENG":"Hey, Deputy. Just got here? I was just placing flowers for the old guys.","TWN":"來了，副團長？我正好在給這些叔叔們獻花呢。"},"stage":{"bg":"TOMB","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아줌마들이 글쎄, 아저씨들이 좋아하는 꽃으로 해달라고 들들 볶는 거 있지? 이거 찾는데 어찌나 오래 걸렸는지.","JPN":"おばさんたちがね、おじさんたちの好きな花にしてくれってうるさくてさ。探すの大変だったよ……","ENG":"The ladies were nagging me nonstop to use their favorite flowers, you know? Took me forever to find them.","TWN":"那些阿姨們居然要求用叔叔們喜歡的花來做裝飾？為了找到這個花，我可是費了好長時間呢。"},"stage":{"bg":"TOMB","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아저씨들은 어차피 꽃 같은 거…….","JPN":"おじさんたちは、どうせお花なんて……","ENG":"They wouldn't even care about flowers like this...","TWN":"叔叔們反正對花什麼的……"},"stage":{"bg":"TOMB","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"신경도… 안 쓸 텐데…….","JPN":"気にも……しないのに……","ENG":"They probably... wouldn't give a damn...","TWN":"他們應該……不會在意……"},"stage":{"bg":"TOMB","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스, 춥지 않아? 이만 들어갈까?","JPN":"アリウス、寒くないですか？　そろそろ中に戻りましょう。","ENG":"Arius, are you cold? Should we head back in?","TWN":"埃里奧斯，不冷嗎？要不要進去？"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"아니에요, 한솔 경. 다른 분들도 괴로운 마음을 꾹 참고 계시는 걸요.","JPN":"いいえ、ヤガミ卿。皆さんも辛いのに我慢しているんですから。","ENG":"No, I'm okay, Sir Hansol. Everyone else is holding back their pain too.","TWN":"不是的，楊瀚。其他人也在忍受痛苦的心情呢。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"이렇게나마 다른 분들의 아픔을 덜어드리고 싶어요.","JPN":"せめて、少しでも痛みを和らげてさしあげたいんです。","ENG":"Even just a little, I want to help ease that pain for them.","TWN":"我希望能以這樣的方式減輕其他人的痛苦。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"…그래. 그래도 무리하지 말아줘.","JPN":"……はい。でも、無理はしないでください。","ENG":"...All right. But don't push yourself too hard.","TWN":"……嗯。不過請不要勉強自己。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"강철 같은 의지와 불굴의 용기를 지녔던 기사들이여.","JPN":"鋼のような意志と、不屈の勇気を抱いていた騎士たちよ。","ENG":"O knights of steel resolve and unyielding courage...","TWN":"擁有鋼鐵般意志和不屈勇氣的騎士們啊。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"비록 그대들은 차갑게 식은 한줌 재로 돌아갔으나.","JPN":"たとえ冷たい灰となり果てようとも。","ENG":"Though you've returned as cold, lifeless ashes...","TWN":"雖然你們已化為冰冷的灰燼。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"그대들이 남긴 각오는, 우리의 길을 밝히는 한 줄기 희망의 별빛이 될 것이다.","JPN":"そなたたちの遺した決意は、我らの進む道を照らす希望の星の光となるだろう。","ENG":"The vow you left behind will shine as a beacon of hope, lighting our path.","TWN":"你們留下的決心，將成為照亮我們道路的一線希望之星光。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"이제는 고된 싸움을 멈추고, 부디 저 하늘의 별이 되어 영원한 평안을 누리길.","JPN":"もう辛い戦いは終え……あの空の星となって、永遠の安らぎを得られよ。","ENG":"Rest now from your weary battles, and may you become stars in the sky, forever at peace.","TWN":"現在請停止艱苦的戰鬥，願你化作天上的星星，享受永恆的安寧。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"……기사단, 전원.","JPN":"……騎士団、全員。","ENG":"...Knights.","TWN":"……騎士團，全員。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"묵념.","JPN":"黙祷。","ENG":"A moment of silence.","TWN":"默哀。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"오지만디아스! 대체 지금 몸상태로 어딜 가신다는 거예요?","JPN":"オジマンディアス！　その体でいったいどこへ行くつもりですか！？","ENG":"Ozymandias! Where do you think you're going in that condition?!","TWN":"奧茲曼迪亞斯！你現在這種身體狀況到底要去哪裡？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"당신은 이 도시에서 유일한 공인 S급 카운터라고요.","JPN":"あなたはこの都市唯一の、公認S級カウンターなんですよ。","ENG":"You are the only Administration confirmed Grade S Counter in this city.","TWN":"你是這座城市唯一公認的S級制裁者。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"시니어 님이 돌아가신 마당에 이런 행패는 안 돼요!","JPN":"シニアが亡くなった今、そんな勝手は許されません！","ENG":"The Senior is dead, and you're acting like this?! Unacceptable!","TWN":"在Senior殉職的情況下，這種行為是不可接受的！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"웃기지 마. 이런 상황에서 두 다리 뻗고 잘 수 있을 것 같아?","JPN":"ふざけないでよ。こんな状況で平然としていられると思う？","ENG":"Don't be ridiculous. You think I can just lie down and sleep through all this?","TWN":"別開玩笑了。在這種情況下，你覺得能安心睡覺嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"다른 사람도 아닌 내가, 중요한 순간에 그런 실수를 저질렀는데……!","JPN":"他でもないこの私が、大事な場面であんな失態を犯したっていうのに……！","ENG":"I'm the one who screwed up at the critical moment...!","TWN":"居然是我，在關鍵時刻犯了這樣的錯誤……！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"오만하군요. 아무리 관리국 공인 S급 카운터라고 해도, 혼자서는 절 막기 힘들 겁니다.","JPN":"傲慢ですね。いくら管理局公認のS級カウンターであっても、一人で私を食い止めるには荷が重いのでは？","ENG":"How arrogant. Even if you are an Administration confirmed Grade S Counter, it'll prove difficult to take me on by yourself.","TWN":"真是傲慢啊。即使你是管理局公認的S級制裁者，一個人也阻止不了我。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"게다가 당신은 이제 챔피언이라는 타이틀도 내려 놓게 되었죠.","JPN":"それにあなたはもうチャンピオンのタイトルも失っている。","ENG":"Plus, you have laid down your title as champion.","TWN":"而且你現在摘下了冠軍的頭銜。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"더는 명예롭지 않은 <color=#ffd34c>오지만디아스</color>라는 이름에 무슨 의미가 있죠?","JPN":"名誉をなくした<color=#ffd34c>オジマンディアス</color>という名に、何の意味があるのですか？","ENG":"What more meaning would the dishonorable name <color=#ffd34c>Ozymandias</color> have now?","TWN":"當<color=#ffd34c>奧茲曼迪亞斯</color>不再榮耀了，這個名字還有什麼意義呢？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"무대 뒤에서 제 얼굴을 본 자는 살려두지 않는 게 원칙이지만.","JPN":"舞台裏で私の顔を見た者を生かしておくのは原則に反しますが、","ENG":"It's my principle to not spare anyone who has seen me behind the stage, but.","TWN":"看到我舞台後真面目的人都必須消失，這是我的原則。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"당신은 절 재미있게 했으니, 특별히 변덕을 부려드리죠.","JPN":"あなたは私を楽しませてくれたので、特別に見逃して差し上げましょう。","ENG":"Since you've entertained me, I'll let you live on a whim.","TWN":"不過你讓我覺得有趣，所以我特別破例一次。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};